    }
    // Compute prefix_max
    val prefix_max = Array.ofDim[Long](n - 1)
    prefix_max(0) = prefix_lengths(0)
    for (i <- 1 until n - 1) {
        prefix_max(i) = Math.max(prefix_max(i - 1), prefix_lengths(i))
    }
    // Compute suffix_max
    val suffix_max = Array.ofDim[Long](n - 1)
    suffix_max(n - 2) = prefix_lengths(n - 2)
    for (i <- n - 3 downTo 0) {
        suffix_max(i) = Math.max(prefix_lengths(i), suffix_max(i + 1))
    }
    // Compute answer
    val answer = Array.ofDim[Long](n)
    for (i <- 0 until n) {
        if (n == 1) {
            answer(i) = 0L
        } else if (n == 2) {
            answer(i) = 0L
        } else {
            var original_max = 0L
            if (i == 0) {
