#include <vector>
#include <string>
#include <algorithm>

using namespace std;

long long get_common_prefix(const string& s, const string& t) {
    long long len = 0;
    while (len < s.length() && len < t.length() && s[len] == t[len]) {
        ++len;
    }
    return len;
}

vector<long long> solve(vector<string> words) {
    int n = words.size();
    if (n <= 1) {
        return vector<long long>(n, 0);
    }
    vector<long long> prefix_lengths(n - 1);
    for (int i = 0; i < n - 1; ++i) {
        prefix_lengths[i] = get_common_prefix(words[i], words[i + 1]);
    }

    // Compute prefix_max array
    vector<long long> prefix_max(n - 1);
    prefix_max[0] = prefix_lengths[0];
    for (int i = 1; i < n - 1; ++i) {
        prefix_max[i] = max(prefix_max[i - 1], prefix_lengths[i]);
    }

    // Compute suffix_max array
    vector<long long> suffix_max(n - 1);
    suffix_max[n - 2] = prefix_lengths[n - 2];
    for (int i = n - 3; i >= 0; --i) {
        suffix_max[i] = max(prefix_lengths[i], suffix_max[i + 1]);
    }

    vector<long long> answer(n);
    for (int i = 0; i < n; ++i) {
        if (n == 1) {
            answer[i] = 0;
        } else if (n == 2) {
            answer[i] = 0;
        } else {
            long long original_max = 0;
            if (i == 0) {
                original_max = (n - 1 >= 2) ? suffix_max[1] : 0;
            } else if (i == n - 1) {
                original_max = (n - 1 >= 2) ? prefix_max[n - 3] : 0;
            } else {
                original_max = max(prefix_max[i - 2], suffix_max[i + 1]);
            }

            long long new_pair = 0;
            if (i > 0 && i < n - 1) {
                new_pair = get_common_prefix(words[i - 1], words[i + 1]);
            }

            answer[i] = max(original_max, new_pair);
        }
    }
    return answer;
}

